function loadWhiteBalance(deviceIp) {
    apiGet('/api/v1/ptz/' + deviceIp + '/image/whitebalance').then(function(r) {
        if (r && r.success && r.data) {
            var wb = r.data;
            deviceImageParams.whiteBalance = wb;

            // 更新模式下拉 - v5.40: 自动(官方)/自动(Astrohub)/手动
            var wbModeSelect = document.getElementById('wbMode');
            if (wbModeSelect) {
                wbModeSelect.innerHTML = '';

                // 选项1: 自动（官方）
                var opt1 = document.createElement('option');
                opt1.value = 'auto_official';
                opt1.textContent = '自动（官方）';
                if (wb.mode === 'auto') opt1.selected = true;
                wbModeSelect.appendChild(opt1);

                // 选项2: 自动
                var opt2 = document.createElement('option');
                opt2.value = 'auto_astrohub';
                opt2.textContent = '自动';
                wbModeSelect.appendChild(opt2);

                // 选项3: 手动
                var opt3 = document.createElement('option');
                opt3.value = 'manual';
                opt3.textContent = '手动';
                if (wb.mode === 'manual') opt3.selected = true;
                wbModeSelect.appendChild(opt3);
            }

            // 更新 R/B 滑动条
            var wbRed = document.getElementById('wbRed');
            var wbBlue = document.getElementById('wbBlue');
            var wbRedVal = document.getElementById('wbRedVal');
            var wbBlueVal = document.getElementById('wbBlueVal');

            if (wbRed && wb.red_gain !== undefined) {
                wbRed.value = wb.red_gain;
                if (wbRedVal) wbRedVal.textContent = wb.red_gain;
            }
            if (wbBlue && wb.blue_gain !== undefined) {
                wbBlue.value = wb.blue_gain;
                if (wbBlueVal) wbBlueVal.textContent = wb.blue_gain;
            }

            // 设置范围
            if (wb.min !== undefined && wb.max !== undefined) {
                if (wbRed) { wbRed.min = wb.min; wbRed.max = wb.max; }
                if (wbBlue) { wbBlue.min = wb.min; wbBlue.max = wb.max; }
            }

            // v5.40: 只有手动模式时 R/B 滑动条才可用
            var isManual = wb.mode === 'manual';
            if (wbRed) wbRed.disabled = !isManual;
            if (wbBlue) wbBlue.disabled = !isManual;
        }
    }).catch(function(e) {
        console.warn('[WB] Load failed:', e);
    });
}

